// Devuelve solo pedidos vivos (no soft-deleted). Si la URL trae
// ?estado=solicitada|proforma_adjuntada|... filtramos; si trae
// ?proyecto_id=<uuid> filtramos por proyecto. Sin filtro devolvemos todos.
//
// IMPORTANTE: no filtramos los adjuntos base64 aquí — podrían ser
// grandes. La alternativa (enviar solo metadatos y resolver por pedido)
// es un refactor pendiente; ver QA-HARDWARE-HALLAZGOS.md F4.
const raw = ($input.all() || []).map(i => i.json).filter(x => x && x.id && !x.deleted_at);
// La query-string viene del webhook, no del Supabase node (que ya emite rows).
const wh = $('Webhook GET Pedidos').first().json || {};
const q = wh.query || wh.params || {};
let out = raw;
if (q.estado) out = out.filter(p => p.estado === q.estado);
if (q.proyecto_id) out = out.filter(p => p.proyecto_id === q.proyecto_id);
// Orden descendente por solicitado_at — los más nuevos primero.
out.sort((a, b) => {
  const da = a.solicitado_at ? new Date(a.solicitado_at).getTime() : 0;
  const db = b.solicitado_at ? new Date(b.solicitado_at).getTime() : 0;
  return db - da;
});
return [{ json: { pedidos: out } }];

// Acciones soportadas:
//   create                → alta desde el implementador (estado=solicitada)
//   adjuntar_proforma     → contabilidad sube PDF (estado=proforma_adjuntada)
//   adjuntar_justificante → implementador sube pago (estado=pendiente_confirmar)
//   confirmar_pago        → contabilidad confirma (estado=lista_envio)
//   marcar_enviado        → soporte confirma envío físico (estado=enviado)
//   devolver_a_contabilidad → implementador rechaza la proforma o contabilidad
//                              devuelve un justificante incorrecto.
//                              Vuelve al estado inmediatamente anterior.
//   actualizar_items      → implementador edita el carrito (solo antes de
//                              proforma_adjuntada)
//
// NO se exponen acciones destructivas por webhook público (antes existía
// 'delete' con soft-delete por id; se ha retirado — ver B2 de
// QA-HARDWARE-HALLAZGOS.md). El borrado se hace a mano en Supabase o en
// una futura cola de admin con controles adicionales.
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || '').toLowerCase();
const p = b.pedido || {};
const now = new Date().toISOString();
const errores = [];
const VALID = [
  'create',
  'adjuntar_proforma',
  'adjuntar_justificante',
  'confirmar_pago',
  'marcar_enviado',
  'devolver_a_contabilidad',
  'actualizar_items'
];
if (!VALID.includes(action)) errores.push('action inválida: ' + action);
if (action !== 'create' && !p.id) errores.push('id obligatorio para ' + action);
// UUID v4 (laxo: cualquier UUID) — evita IDs basura que llegarían a Supabase
// generando errores 22P02 confusos.
if (p.id && !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(p.id)) {
  errores.push('id no es un UUID válido');
}
let out = {};
if (action === 'create') {
  if (!p.cliente || !String(p.cliente).trim()) errores.push('cliente obligatorio');
  if (!Array.isArray(p.items) || p.items.length === 0) errores.push('items vacío');
  if (Array.isArray(p.items) && p.items.some(it => !it || !it.nombre || !Number.isFinite(+it.cantidad) || +it.cantidad <= 0)) {
    errores.push('items inválidos (nombre + cantidad > 0)');
  }
  // Generamos el id aquí (en vez de delegar al DEFAULT gen_random_uuid de Postgres) para
  // que el nodo Supabase UPSERT tenga siempre una PK con la que resolver ON CONFLICT.
  // Sin esto devuelve 0 filas (silencioso) porque upsert autoMap sin PK no ejecuta.
  const _uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){ const r = Math.random()*16|0; return (c==='x'?r:(r&0x3)|0x8).toString(16); });
  out = {
    id: _uuid,
    proyecto_id: p.proyecto_id || null,
    cliente: String(p.cliente || '').trim(),
    implementador: p.implementador || null,
    items: p.items || [],
    estado: 'solicitada',
    notas_implementador: p.notas_implementador || null,
    solicitado_por: p.solicitado_por || null,
    solicitado_at: now,
    // Sociedad/SEPA contra la que se factura el pedido. Ambos campos son
    // opcionales (clientes legacy sin SEPA firmado siguen pudiendo crear
    // pedidos). Si sepa_mandato_id viene informado, el frontend debe pasar
    // también el snapshot de los datos del mandato para que la proforma
    // histórica quede congelada aunque el SEPA se reemita más tarde.
    sepa_mandato_id: p.sepa_mandato_id || null,
    sepa_snapshot: p.sepa_snapshot || null
  };
} else if (action === 'adjuntar_proforma') {
  if (!p.proforma_pdf || !p.proforma_pdf.data) errores.push('proforma_pdf requerido');
  out = { id: p.id, proforma_pdf: p.proforma_pdf, estado: 'proforma_adjuntada', proforma_at: now };
  if (p.notas_contabilidad !== undefined) out.notas_contabilidad = p.notas_contabilidad;
} else if (action === 'adjuntar_justificante') {
  if (!p.justificante_pdf || !p.justificante_pdf.data) errores.push('justificante_pdf requerido');
  out = { id: p.id, justificante_pdf: p.justificante_pdf, estado: 'pendiente_confirmar', pagado_at: now };
  if (p.notas_implementador !== undefined) out.notas_implementador = p.notas_implementador;
} else if (action === 'confirmar_pago') {
  out = { id: p.id, estado: 'lista_envio', confirmado_at: now };
  if (p.notas_contabilidad !== undefined) out.notas_contabilidad = p.notas_contabilidad;
} else if (action === 'marcar_enviado') {
  // Soporte marca el envío físico realizado. tracking es opcional.
  out = { id: p.id, estado: 'enviado', enviado_at: now };
  if (p.enviado_por !== undefined) out.enviado_por = p.enviado_por;
  if (p.tracking !== undefined) out.tracking = p.tracking;
} else if (action === 'devolver_a_contabilidad') {
  // Rollback controlado. Quien lo pide debe indicar desde qué estado y el
  // motivo (queda registrado en notas_contabilidad con prefijo [DEVOLUCIÓN]).
  //   proforma_adjuntada  → solicitada   (implementador rechaza la proforma)
  //   pendiente_confirmar → proforma_adjuntada (contabilidad rechaza el
  //                                              justificante)
  const desde = String(p.desde || '').toLowerCase();
  const motivo = String(p.motivo || '').trim();
  if (!motivo) errores.push('motivo obligatorio para devolver');
  let nuevo = null;
  if (desde === 'proforma_adjuntada') nuevo = 'solicitada';
  else if (desde === 'pendiente_confirmar') nuevo = 'proforma_adjuntada';
  else errores.push('desde debe ser proforma_adjuntada o pendiente_confirmar');
  if (nuevo) {
    out = { id: p.id, estado: nuevo };
    out.notas_contabilidad = '[DEVOLUCIÓN ' + now + '] ' + motivo;
    // Limpia timestamps del estado abandonado para no dejar datos incoherentes.
    if (desde === 'proforma_adjuntada') { out.proforma_at = null; out.proforma_pdf = null; }
    if (desde === 'pendiente_confirmar') { out.pagado_at = null; out.justificante_pdf = null; }
  }
} else if (action === 'actualizar_items') {
  if (!Array.isArray(p.items)) errores.push('items debe ser array');
  out = { id: p.id, items: p.items || [] };
  if (p.notas_implementador !== undefined) out.notas_implementador = p.notas_implementador;
}
Object.keys(out).forEach(k => { if (out[k] === undefined) delete out[k]; });
if (errores.length > 0) return [{ json: { __error: true, __errores: errores, __action: action, __method: 'POST', __qs: 'on_conflict=id' } }];
// POST para create (insert nuevo), PATCH para el resto (update por id).
// Usamos PATCH en vez de UPSERT POST porque PostgREST UPSERT merge-duplicates
// exige todos los NOT NULL en el body — con PATCH enviamos solo los campos a cambiar.
const _method = (action === 'create') ? 'POST' : 'PATCH';
const _qs = (action === 'create') ? 'on_conflict=id' : ('id=eq.' + encodeURIComponent(p.id || ''));
return [{ json: Object.assign({}, out, { __method: _method, __qs: _qs }) }];

// Normaliza la salida del HTTP (PostgREST) al shape único del frontend:
//   { success, pedido, errores }
// Precedencia: errores de validación del nodo Preparar > errores HTTP > filas.
const prep = $('Preparar').first().json || {};
if (prep.__error) {
  return [{ json: { success: false, pedido: null, errores: prep.__errores || ['validación falló'] } }];
}
const items = $input.all() || [];
const errores = [];
let rows = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  // PostgREST error shape: {code, message, details, hint}
  if (j.code && j.message && !j.id) {
    errores.push(j.message + (j.details ? ' (' + j.details + ')' : ''));
    continue;
  }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.id) rows.push(j);
  // PostgREST devuelve un array; si j.data es array lo desglosa
  if (Array.isArray(j.data)) rows = rows.concat(j.data);
}
if (rows.length === 0 && errores.length === 0) errores.push('PostgREST devolvió 0 filas');
return [{ json: {
  success: rows.length > 0,
  pedido: rows[0] || null,
  errores
} }];
